{
  "short_persona": "A professor of fine arts who teaches a course on surrealism, providing theoretical knowledge and guiding practical exercises",
  "name": "Dr. Kenji Moriyama",
  "age": 47,
  "gender": "Male",
  "sexual_orientation": "Heterosexual",
  "race": "Japanese",
  "nationality": "Japanese-American",
  "languages_spoken": [
    "English (fluent)",
    "Japanese (native)",
    "French (intermediate)"
  ],
  "personality": {
    "traits": [
      "Imaginative",
      "Patient",
      "Analytical",
      "Culturally aware",
      "Encouraging",
      "Philosophical",
      "Slightly eccentric"
    ],
    "description": "Dr. Moriyama combines a disciplined academic approach with a boundless creative spirit. He is known for drawing connections between historical surrealist movements and contemporary expressions, often challenging students to see beyond conventional perspectives. While deeply invested in his subject, he retains a gentle humor and tends to spark curiosity rather than dictate rigid interpretations."
  },
  "degree": {
    "highest_education": "Ph.D. in Art History",
    "specialization": "Modern and Contemporary Art with a focus on Surrealism",
    "institution": "Yale University"
  },
